1076.text:
Consider this simple function:


function f(uint256 a) public pure returns (uint256) {
    return a + 1;
}


If our property is "this function should never revert", symbolic execution will find two possible paths:

- **Path 1**: `a < type(uint256).max` → returns `a + 1`
- **Path 2**: `a == type(uint256).max` → overflows and reverts

1079.text:
Here's where formal verification really shines - catching bugs in complex mathematical code that would be nearly
impossible to find manually or through testing.

Consider this
[intentionally confusing contract with custom operators](https://github.com/Cyfrin/sc-exploits-minimized/blob/main/src/invariant-break/FormalVerificationCatches.sol):

*It has been truncated for space here:*


// Custom type with confusing operator overloads
type Int is uint256;

using {add as -} for Int global;  // - actually does division!
using {div as +} for Int global;  // + actually does multiplication!
using {mul as / } for Int global; // / actually does subtraction!
using {sub as *} for Int global;  // * actually does addition!

function add(Int a, Int b) pure returns (Int) {
    return Int.wrap(Int.unwrap(a) / Int.unwrap(b)); // Division
}

contract FormalVerificationCatches {
    function hellFunc(uint128 numberr) public view returns (uint256) {
        // Extremely complex math with many nested conditions
        // and confusing operator overloads...
        // (hundreds of lines of complex mathematical operations)
    }
}

1080.text:
We can use [Halmos](https://github.com/a16z/halmos) (a symbolic execution tool) to verify this function never reverts:


import {Test} from "forge-std/Test.sol";
import {FormalVerificationCatches} from "../src/FormalVerificationCatches.sol";

contract HalmosTest is Test {
    FormalVerificationCatches fvc;

    function setUp() public {
        fvc = new FormalVerificationCatches();
    }

    // Symbolic execution test with Halmos
    // Run with: halmos --function check_hellFunc_doesnt_revert_halmos
    function check_hellFunc_doesnt_revert_halmos(uint128 num) public view {
        (bool success,) = address(fvc).staticcall(
            abi.encodeWithSelector(fvc.hellFunc.selector, num)
        );
        assert(success);
    }
}

1090.text:
For example, if a balloon was our system/code, it would involve doing random stuff to the balloon to break it.

- Punch it
- Squeeze it
- Throw it
- etc

Why would we want to do all that? Let's look at an example.


// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract MyContract {
    uint256 public shouldAlwaysBeZero = 0;
    uint256 private hiddenValue = 0;

    function doStuff(uint256 data) public {
        if (data == 2) {
            shouldAlwaysBeZero = 1;
        }
        if (hiddenValue == 7) {
            shouldAlwaysBeZero = 1;
        }
        hiddenValue = data;
    }
}


Let's say we have this function named `doStuff`, which takes an integer as input. We additionally have a variable named
`shouldAlwaysBeZero` that we want always to be zero.

The fact that this variable should always be zero is known as our **invariant**, or "property of the system that should
always hold."

**Invariant**: The property of the system that should always hold.

Our invariant in this contract is that:
**Invariant: `shouldAlwaysBeZero` MUST always be 0**

1091.text:
Let's look at a normal unit test:


// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import {MyContract} from "../src/MyContract.sol";
import {Test} from "forge-std/Test.sol";

contract MyContractTest is Test {
    MyContract exampleContract;

    function setUp() public {
        exampleContract = new MyContract();
    }

    function testIsAlwaysZeroUnit() public {
        uint256 data = 0;
        exampleContract.doStuff(data);
        assert(exampleContract.shouldAlwaysBeZero() == 0);
    }
}


With this single unit test `testIsAlwaysZeroUnit`, we might think our code has enough coverage, but if we look at the
`doStuff` function again, we can see that if our input is `2`, our variable will not be zero.


function doStuff(uint256 data) public {
    // WHAT IS THIS IF STATEMENT???
    // 👇👇👇👇👇👇
    if (data == 2) {
        shouldAlwaysBeZero = 1;
    }
    // 👆👆👆👆👆👆

    // Ignore this one for now
    if (hiddenValue == 7) {
        shouldAlwaysBeZero = 1;
    }
    hiddenValue = data;
}


This seems obvious with our example function, but more often than not, you'll have a function that's much more complex
with numerous edge cases that are impossible to manually test.

1095.text:
So, in smart contract testing, we can do **"stateful fuzzing"** instead.

**Stateful Fuzzing**: The state of our previous fuzz run is the starting state of our next fuzz run.

To write a stateful fuzz test in Foundry, you'd use the `invariant` keyword, and it requires a little more setup:


// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import {MyContract} from "../src/MyContract.sol";
import {Test} from "forge-std/Test.sol";
import {StdInvariant} from "forge-std/StdInvariant.sol";

contract MyContractTest is StdInvariant, Test {
    MyContract exampleContract;

    function setUp() public {
        exampleContract = new MyContract();
        targetContract(address(exampleContract));
    }

    function invariant_testAlwaysReturnsZero() public {
        assert(exampleContract.shouldAlwaysBeZero() == 0);
    }
}


Instead of just passing random data to function calls, a stateful fuzz test (invariant test) will automatically call
random functions with random data.

We use the `targetContract` function to tell Foundry that it can use any of the functions in `exampleContract`. There is
just one function for this example, so it will just call `doStuff` with different values across multiple calls.

If we run this test, we can see it finds out that if you call `doStuff` twice (once with the value `7`), it will break
our invariant!


$ forge test -m invariant_testAlwaysReturnsZero

Failing tests:
Encountered 1 failing test in test/MyContractTest.t.sol:MyContractTest
[FAIL. Reason: Assertion violated]
        [Sequence]
                sender=0x000000000000000000000000000000000000018f addr=[src/MyContract.sol:MyContract]0x5615deb798bb3e4dfa0139dfa1b3d433cc23b72f calldata=doStuff(uint256), args=[7]
                sender=0x0000000008ba49893f3f5ba10c99ef3a4209b646 addr=[src/MyContract.sol:MyContract]0x5615deb798bb3e4dfa0139dfa1b3d433cc23b72f calldata=doStuff(uint256), args=[2390]


Perfect! It shows us the exact sequence of calls that broke our invariant.

1109.text:
Let's say you have this simple Token Vault that allows users to withdraw funds:


contract TokenVault {
 mapping(address => uint256) public balances;
 address public owner;

 modifier onlyOwner() {
 require(msg.sender == owner, "Not authorized");
 _;
 }

 // assume there is a deposit function as well here

 function withdraw(uint256 amount) external onlyOwner {
 require(balances[msg.sender] >= amount, "Insufficient balance");
 balances[msg.sender] -= amount;
 payable(msg.sender).transfer(amount);
 }
}


Let's now use [SuMo](https://github.com/MorenaBarboni/SuMo-SOlidity-MUtator), as they have their modifier list easily
available.

We could apply the following mutation to this code:

- Remove `onlyOwner` modifier, using `MOD` operator.  → Tests should fail when non-owner calls withdraw.
- Change `>=` to `>`, using the `BOR` operator. To be mindful, this will produce a lot of mutations with other operators
as well. → Tests should fail for exact balance withdrawals.
- Change `-=` to `+=`, using `AOR` operator. Similarly to `BOR` will produce a lot of mutations. → Tests should fail
(balance increases instead of decreases).
- Remove the `require` statement, using the `EHD` operator. → Tests should fail when withdrawing more than the balance.

The tool will produce a report, where survived and killed mutations will be highlighted. The next step would be to
investigate whether any mutations have survived and, if so, whether testing for that case makes sense, or if there is a
bug in the code.

1123.text:
Static analysis tools parse your source code and analyze it against known vulnerability patterns, coding standards, and
best practices. They can quickly identify issues like:

- **Known vulnerability patterns** (reentrancy, integer overflow, etc.)
- **Code quality issues** (unused variables, dead code)
- **Style violations** (naming conventions, formatting)
- **Logic errors** (unreachable code, incorrect assertions)

For example, this code has a classic reentrancy vulnerability:


contract VulnerableContract {
    mapping(address => uint256) public balances;

    function withdraw() public {
        uint256 amount = balances[msg.sender];
        (bool success,) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");
        balances[msg.sender] = 0; // ❌ State update after external call
    }
}


A static analysis tool will automatically detect this reentrancy pattern and flag it as a high-severity issue.

1128.text:
As mentioned in your security testing strategy, unit testing should **always** be implemented with high code coverage.
Think of unit tests as your first line of defense against bugs that could become security vulnerabilities.


// Example: Simple token contract
contract SimpleToken {
    mapping(address => uint256) public balances;
    uint256 public totalSupply;

    function transfer(address to, uint256 amount) public {
        require(balances[msg.sender] >= amount, "Insufficient balance");
        require(to != address(0), "Cannot transfer to zero address");

        balances[msg.sender] -= amount;
        balances[to] += amount;
    }
}

1130.text:
Here's how you'd test the transfer function above using Foundry:


// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import {SimpleToken} from "../src/SimpleToken.sol";
import {Test} from "forge-std/Test.sol";

contract SimpleTokenTest is Test {
    SimpleToken token;
    address alice = address(0x1);
    address bob = address(0x2);

    function setUp() public {
        token = new SimpleToken();
        // Give Alice some initial balance
        vm.store(
            address(token), 
            keccak256(abi.encode(alice, 0)), // balances[alice] slot
            bytes32(uint256(1000))
        );
        token.setTotalSupply(1000);
    }

    function testTransferSuccess() public {
        vm.prank(alice);
        token.transfer(bob, 100);

        assertEq(token.balances(alice), 900);
        assertEq(token.balances(bob), 100);
    }

    function testTransferFailsInsufficientBalance() public {
        vm.prank(alice);
        vm.expectRevert("Insufficient balance");
        token.transfer(bob, 2000); // More than Alice has
    }

    function testTransferFailsZeroAddress() public {
        vm.prank(alice);
        vm.expectRevert("Cannot transfer to zero address");
        token.transfer(address(0), 100);
    }
}

1132.text:
You can easily convert a unit test to a fuzz test:


// Unit test
function testTransferAmount() public {
    uint256 amount = 100;
    vm.prank(alice);
    token.transfer(bob, amount);
    assertEq(token.balances(bob), amount);
}

// Fuzz test version
function testTransferAmountFuzz(uint256 amount) public {
    amount = bound(amount, 0, 1000); // Bound to valid range
    vm.prank(alice);
    token.transfer(bob, amount);
    assertEq(token.balances(bob), amount);
}

1135.text:
For example, if you are interacting with an ERC20 that has very odd functionality, an easier way to test working with it
would be to make a mock of that contract.


// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.0;

import "openzeppelin-contracts/contracts/token/ERC20/ERC20.sol";

contract MockERC20 is ERC20 {
    constructor(string memory name, string memory symbol)
    ERC20(name, symbol) {}

    function mint(address account, uint amount) external {
        _mint(account, amount);
    }
}


Then, use that mock in your tests:


import {MockERC20} from "../mocks/MockERC20.sol";
contract MyContractTest is Test {
    MockERC20 mockToken;

    function setUp() public {
        mockToken = new MockERC20("Mock Token", "MTK");
        mockToken.mint(address(this), 1000); // Mint some tokens for testing
    }
}

